//Do Case
//	Case &mode = TrnMode.Update
		For Each Order EmpCod, FilCod, PedCod
			Where EmpCod = &EmpCod
			Where FilCod = &FilCod
			Where PedCod = &PedCod

			&OldTabCod = TabCod 
			&OldTabPrmCod = TabPrmCod 
			&oldTabColCod = TabColCod
			&OldLctCod = LctCod
			&OldPedDtaVct = PedDtaVct

			PedCliCod = &sdtGravaPedido.PedCliCod
			PedRspCod = &sdtGravaPedido.PedRspCod

			PedNovCliRaz = RetiraCaracteresEspeciais.Udp(&sdtGravaPedido.PedNovCliRaz)
			PedNovCliCpfCnpj = &sdtGravaPedido.PedNovCliCpfCnpj

			if PedNovCliCpfCnpj.Length() = 18 //'21.826.923/0001-77' //JURIDICA
				PedNovTip = TipoPessoa.JURIDICA
			Else
				PedNovTip = TipoPessoa.FISICA
			Endif

			LctCod = &sdtGravaPedido.LctCod

			prcRetornaDadosTipoLancamento.Call(&EmpCod, &sdtGravaPedido.LctCod, &LctUntArr)
			PedLctUntArr = &LctUntArr

			PedDtaEms = &sdtGravaPedido.PedDtaEms
			PedDtaPrv = &sdtGravaPedido.PedDtaPrv
			TabCod = &sdtGravaPedido.TabCod
			TabPrmCod = &sdtGravaPedido.TabPrmCod

			TabColCod = &sdtGravaPedido.TabColCod

			PedNum = &sdtGravaPedido.PedNum			
			PedVenCod = &sdtGravaPedido.PedVenCod		

			//FINANCEIRO
			PedPraCod = &sdtGravaPedido.PedPraCod
			PedFrpPgtoCod = &sdtGravaPedido.PedFrpPgtocod
			PedPraParNom = &sdtGravaPedido.PedPraParNom


			PedAnoSaf = &sdtGravaPedido.PedAnoSaf
			PedAnoOrc = &sdtGravaPedido.PedAnoOrc
			PedTlvCod = &sdtGravaPedido.PedTlvCod

			//TRANSPORTE
			PedTraRedCod = &sdtGravaPedido.PedTraRedCod
