			PedRomCrt = &sdtGravaPedido.PedRomCrt

			PedObsEst = &sdtGravaPedido.PedObsEst
			PedObsFin = &sdtGravaPedido.PedObsFin
			PedObsGer = &sdtGravaPedido.PedObsGer
			PedObsNfe = &sdtGravaPedido.PedObsNfe

			PedTpcCod = &sdtGravaPedido.PedTpcCod
			PedFatFilCod = &sdtGravaPedido.PedFatFilCod

			//TOTAIS
			PedVlrDscGlb = &sdtGravaPedido.PedVlrDscGlb
			PedVlrOutCus = &sdtGravaPedido.PedVlrOutCus
			PedVlrGnre = &sdtGravaPedido.PedVlrGnre
