			PedPerSpm1 = &sdtGravaPedido.PedPerSpm1
			PedPerSpm2 = &sdtGravaPedido.PedPerSpm2

			PedPerPrm1 = &sdtGravaPedido.PedPerPrm1
			PedPerPrm2 = &sdtGravaPedido.PedPerPrm2

			PedPrpCod = &sdtGravaPedido.PedPrpCod

			PedCodOciRef = &sdtGravaPedido.PedCodOciRef

			PedCbrCod = &sdtGravaPedido.PedCbrCod
			PedCtaBanCod = &sdtGravaPedido.PedCtaBanCod

			PedEnvCod = &sdtGravaPedido.PedEnvCod

			PedCodOciRef = &sdtGravaPedido.PedCodOciRef

			PedCliNfeCod = &sdtGravaPedido.PedCliNfeCod

			PedEmbDes = &sdtGravaPedido.PedEmbDes

			PedDtaVct = &sdtGravaPedido.PedDtaVct

			PedIsImpCot = &sdtGravaPedido.PedIsImpCot

			PedPraParDesc = &sdtGravaPedido.PedPraParDesc
			Exit
		EndFor

